        var result = _serviceS.WFiltroOperadorEMailPopup(filtro);
        // Assert
        result.Should().NotBeNull();
        // Check parameter
        var QuemCadParameter = result.Value.parametros.FirstOrDefault(p => p.ParameterName == $"@{DBOperadorEMailPopupDicInfo.QuemCad}");
